//Swiper Services
document.addEventListener("DOMContentLoaded", function () {
  const swiperEl = document.querySelector(".swiper");
  if (swiperEl) swiperEl.setAttribute("tabindex", "0");

  const swiper = new Swiper(".swiper", {
    loop: false,
    speed: 500,
    slidesPerView: "auto",
    spaceBetween: 24,
    centeredSlides: true,
    centeredSlidesBounds: true,
    slideToClickedSlide: true,
    allowTouchMove: true,
    slidesOffsetAfter: 64,

    keyboard: {
      enabled: true,
      onlyInViewport: true,
      pageUpDown: true
    },

    a11y: {
      enabled: true
    },

    pagination: {
      el: ".swiper-pagination",
      clickable: true
    },

    navigation: {
      nextEl: ".product_next",
      prevEl: ".product_prev"
    },

    breakpoints: {
      768: {
        slidesPerView: "auto",
        spaceBetween: 24,
        centeredSlides: false,
        centeredSlidesBounds: false
      },
      1280: {
        slidesPerView: "auto",
        spaceBetween: 32,
        centeredSlides: false,
        slidesOffsetAfter: 228,
        centeredSlidesBounds: false
      }
    }
  });

  document.querySelectorAll(".swiper-slide.is--product").forEach((slide, i) => {
    slide.setAttribute("tabindex", "0");
    slide.addEventListener("keydown", (e) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        swiper.slideTo(i);
      }
    });
  });
});

//Swiper Team
document.addEventListener("DOMContentLoaded", function () {
  const swiperEl = document.querySelector(".swiper-team");
  if (!swiperEl) return;

  new Swiper(swiperEl, {
    loop: false,
    speed: 700,
    slidesPerView: 1,
    slidesPerGroup: 1,
    spaceBetween: 16,
    centeredSlides: false,
    centeredSlidesBounds: false,
    slideToClickedSlide: false,
    allowTouchMove: true,
    watchOverflow: true,
    observer: true,
    observeParents: true,

    navigation: {
      nextEl: ".team-next",
      prevEl: ".team-prev"
    },

    breakpoints: {
      768: {
        slidesPerView: 1,
        spaceBetween: 24
      },
      1280: {
        slidesPerView: 3,
        spaceBetween: 24
      },
      1440: {
        slidesPerView: 2,
        spaceBetween: 24
      },
      1920: {
        slidesPerView: 3,
        spaceBetween: 24
      }
    }
  });
});

//Zoom image card
document.addEventListener("DOMContentLoaded", () => {
  const teamCards = document.querySelectorAll(".slide_inner.is--team");

  teamCards.forEach((card) => {
    const img = card.querySelector(".people_img");

    card.addEventListener("mouseenter", () => {
      if (img) {
        gsap.to(img, {
          scale: 1.05,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });

    card.addEventListener("mouseleave", () => {
      if (img) {
        gsap.to(img, {
          scale: 1,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });
  });
});
